import React from  "react";
import { observer } from "mobx-react"

const All = observer((user) =>(
    <div className="portfolio-content">
       <h2>This page is {console.log(user)}</h2>
        <h3>{user.appData.count}</h3>
        <button onClick={user.inCount}>Inc</button>
        <button onClick={user.deCount}>Dec</button>
    </div>
))

export default All;