import React from "react";
import {NavLink, Route, Redirect} from "react-router-dom";
import { observable } from "mobx";


import All from "./portfolios/all";
import {CSSCourses, HTMLCourses, ReactCourses} from '../data/portfoliodata';

var appState = observable({
    count: 0,
    Inc: ()=>{
        return appState.count += 1;
    },
    Dec: ()=>{
        return appState.count -= 1;
    }
})

const Portfolio = (props) => {
    var match = props.match;

    return(
        <div className="main-content">
            <h1>Portfolio</h1>
            <ul className="nav d-flex">
                <li><NavLink exact to={`${match.url}/html`}>HTML</NavLink></li>
                <li><NavLink to={`${match.url}/css`}>CSS </NavLink></li>
                <li><NavLink to={`${match.url}/react`}>React</NavLink></li>
            </ul>
            <hr/>
            <Route exact path={`${match.path}/:course`} render={(props) => (<All
            {...props}
            data={CSSCourses} inCount={appState.Inc} deCount={appState.Dec} appData={appState}/>)}/>
        </div>
    )
}




export default Portfolio;